/* ---- risk tiers ---- */
var RISK={};
function setR(t,list){ list.split(' ').forEach(function(c){ RISK[c]=t; }); }
setR('critical','SYR YEM AFG SOM SSD LBY UKR');
setR('severe','IRN IRQ SDN COD NGA MLI NER TCD CAF PAK MMR VEN ETH ERI BFA CMR MOZ');
setR('high','BRA USA RUS CHN IND MEX ARG ZAF SAU EGY IDN COL KAZ MNG TUR DZA AGO PHL THA KEN TZA LBR GIN ZWE BOL PER MRT');
setR('moderate','AUS CHL ECU MAR TUN OMN ARE VNM LKA BGD GHA ZMB NAM BWA PRY URY KHM LAO NPL AZE GEO JOR ISR KWT QAT BHR TKM UZB KGZ TJK SEN CIV TGO BEN GAB COG MDG MWI RWA UGA BDI');
setR('low','CAN FRA DEU ESP ITA POL GBR IRL JPN KOR AUT CHE BEL NLD CZE SVK HUN ROU BGR GRC PRT HRV SRB');
setR('negligible','NOR SWE FIN DNK ISL NZL LUX EST LVA LTU SVN SGP');
var RMAP={critical:['#ec3b34',.78],severe:['#e2407a',.7],high:['#f4a92b',.6],moderate:['#f5d44a',.4],low:['#37d39b',.16],negligible:['#8a98b5',.1]};
function riskFill(id){ var t=RISK[id]||'low'; return RMAP[t]||RMAP.low; }
function hexToRgb(h){h=h.replace('#','');return [parseInt(h.substr(0,2),16),parseInt(h.substr(2,2),16),parseInt(h.substr(4,2),16)];}
function rgba(hex,a){var c=hexToRgb(hex);return 'rgba('+c[0]+','+c[1]+','+c[2]+','+a+')';}
function mix(h1,h2,t){var a=hexToRgb(h1),b=hexToRgb(h2);return 'rgb('+Math.round(a[0]+(b[0]-a[0])*t)+','+Math.round(a[1]+(b[1]-a[1])*t)+','+Math.round(a[2]+(b[2]-a[2])*t)+')';}

/* ---- real vessel icon from the live portal (recoloured per vessel) ---- */
var SHIP_IMG_SRC="data:image/png;base64,";
var shipImg=new Image(), shipImgReady=false, shipTintCache={}, mapDraws=[];
shipImg.onload=function(){ shipImgReady=true; for(var i=0;i<mapDraws.length;i++){ try{ mapDraws[i](); }catch(e){} } };
shipImg.src=SHIP_IMG_SRC;
var PIL_LOGO_SRC="data:image/png;base64,";
var pilLogoImg=new Image(), pilLogoReady=false;
pilLogoImg.onload=function(){ pilLogoReady=true; for(var i=0;i<mapDraws.length;i++){ try{ mapDraws[i](); }catch(e){} } };
pilLogoImg.src=PIL_LOGO_SRC;
function tintedShip(color){
  if(shipTintCache[color]) return shipTintCache[color];
  var iw=shipImg.naturalWidth||200, ih=shipImg.naturalHeight||200;
  var oc=document.createElement('canvas'); oc.width=iw; oc.height=ih;
  var octx=oc.getContext('2d'); octx.drawImage(shipImg,0,0);
  octx.globalCompositeOperation='source-in'; octx.fillStyle=color; octx.fillRect(0,0,iw,ih);
  shipTintCache[color]=oc; return oc;
}

/* ---- progress + sticky header ---- */
var prog=document.getElementById('progress'), topbar=document.getElementById('topbar');
function onScroll(){ var st=window.pageYOffset||0, h=document.documentElement.scrollHeight-window.innerHeight; prog.style.width=(h>0?(st/h*100):0)+'%'; if(st>40)topbar.classList.add('solid'); else topbar.classList.remove('solid'); }
window.addEventListener('scroll',onScroll,{passive:true}); onScroll();

