/* ---- map factory ---- */
function makeMap(canvas,opts){
  opts=opts||{};
  var ctx=canvas.getContext('2d'); var DPR=Math.min(window.devicePixelRatio||1,2);
  var W=0,H=0,worldW=0,worldH=0,paths=[];
  var cam={cx:.52,cy:.5,zoom:1.06}, tgt={cx:.52,cy:.5,zoom:1.06}, base={cx:.52,cy:.5,zoom:1.06};
  var choro=false, choroT=0, highlights=[], routes=[], vessels=[], t=0, raf=null, running=false, hitList=[], hoverCb=null, lastHover=null, hoverM=null, hoverP=0;
  function nx(lon){return (lon+180)/360;} function ny(lat){return (90-lat)/180;}
  function pw(lon,lat){return [nx(lon)*worldW, ny(lat)*worldH];}
  function buildPaths(){
    paths=[];
    if(!GEO) return;
    GEO.features.forEach(function(f){
      var p=new Path2D(), g=f.geometry; if(!g) return;
      var polys = g.type==='Polygon'?[g.coordinates]:g.coordinates;
      polys.forEach(function(poly){ poly.forEach(function(ring){ for(var i=0;i<ring.length;i++){ var xy=pw(ring[i][0],ring[i][1]); if(i===0)p.moveTo(xy[0],xy[1]); else p.lineTo(xy[0],xy[1]); } p.closePath(); }); });
      paths.push({id:f.id,p:p});
    });
  }
  function resize(){ var r=canvas.getBoundingClientRect(); W=Math.max(2,r.width); H=Math.max(2,r.height); canvas.width=Math.round(W*DPR); canvas.height=Math.round(H*DPR); worldW=W; worldH=W/2; buildPaths(); }
  function bez(a,b,c,u){var m=1-u;return [m*m*a[0]+2*m*u*c[0]+u*u*b[0], m*m*a[1]+2*m*u*c[1]+u*u*b[1]];}
  function ctrl(a,b){var mx=(a[0]+b[0])/2,my=(a[1]+b[1])/2,dx=b[0]-a[0],dy=b[1]-a[1],d=Math.sqrt(dx*dx+dy*dy);return [mx,my-Math.min(d*.3,140)];}
  function drawShipIcon(x,y,col,headingDeg,px,badge){
    if(!shipImgReady){ ctx.beginPath(); ctx.arc(x,y,3/cam.zoom,0,6.2832); ctx.fillStyle=col; ctx.fill(); return; }
    var spr=tintedShip(col), w=px/cam.zoom, h=w*(spr.height/spr.width||1);
    /* vessel sprite sits in the centre band of a square PNG; visible hull ≈ middle 44% */
    var east=(headingDeg>0 && headingDeg<180); /* PNG bow faces left; flip for eastbound */
    ctx.save(); ctx.translate(x,y); if(east) ctx.scale(-1,1);
    ctx.shadowColor=col; ctx.shadowBlur=8;
    ctx.drawImage(spr,-w/2,-h/2,w,h);
    ctx.restore();
    /* PIL fleet badge stacked above the hull (upright, never flipped) — mirrors the live portal */
    if(badge && pilLogoReady){
      var lw=(px*0.92)/cam.zoom, lh=lw*((pilLogoImg.naturalHeight/pilLogoImg.naturalWidth)||0.3125);
      var by=-h*0.18-lh; /* bottom of badge just above the hull top */
      ctx.save(); ctx.translate(x,y);
      ctx.shadowColor='rgba(2,6,14,.85)'; ctx.shadowBlur=5; ctx.shadowOffsetY=1/cam.zoom;
      ctx.drawImage(pilLogoImg,-lw/2,by,lw,lh);
      ctx.restore();
    }
  }
  function drawHoverFx(x,y,col,isShip){
    var z=cam.zoom, p=Math.max(0.001,hoverP);
    var R=(isShip?23:16)/z;
    var g=ctx.createRadialGradient(x,y,0,x,y,R);
    g.addColorStop(0,rgba(col,0.34*p)); g.addColorStop(0.55,rgba(col,0.12*p)); g.addColorStop(1,rgba(col,0));
    ctx.beginPath(); ctx.fillStyle=g; ctx.arc(x,y,R,0,6.2832); ctx.fill();
    for(var k=0;k<2;k++){ var ph=((t*0.9)+k*0.5)%1; var rr=((isShip?11:8)+ph*16)/z; ctx.beginPath(); ctx.arc(x,y,rr,0,6.2832); ctx.strokeStyle=rgba(col,0.5*(1-ph)*p); ctx.lineWidth=1.4/z; ctx.stroke(); }
    var fr=((isShip?13:10)*p)/z; ctx.beginPath(); ctx.arc(x,y,fr,0,6.2832); ctx.strokeStyle=rgba(col,0.85*p); ctx.lineWidth=1.6/z; ctx.stroke();
  }
  function markers(arr,hi){
    for(var i=0;i<arr.length;i++){ var m=arr[i], xy=pw(m.lon,m.lat), col=m.color||'#3fb9f5', big=hi||m.big, hov=(m===hoverM);
      if(hov) drawHoverFx(xy[0],xy[1],col,m.ship);
      if(m.ship){
        if(!reduce){ var spr2=(t*0.8+i)%2, sr=((big?7:5)+spr2*8)/cam.zoom, sa=Math.max(0,0.45-spr2*0.22); ctx.beginPath(); ctx.arc(xy[0],xy[1],sr,0,6.2832); ctx.strokeStyle=rgba(col,sa); ctx.lineWidth=1/cam.zoom; ctx.stroke(); }
        drawShipIcon(xy[0],xy[1],col,m.heading,(big?34:27)*(hov?1.16:1),m.badge);
      } else {
        if(!reduce){ var pr=(t*0.8+i)%2, rr=((big?5:3)+pr*7)/cam.zoom, al=Math.max(0,0.5-pr*0.25); ctx.beginPath(); ctx.arc(xy[0],xy[1],rr,0,6.2832); ctx.strokeStyle=rgba(col,al); ctx.lineWidth=1/cam.zoom; ctx.stroke(); }
        ctx.beginPath(); ctx.arc(xy[0],xy[1],((big?6:4))/cam.zoom,0,6.2832); ctx.strokeStyle=rgba(col,.35); ctx.lineWidth=1/cam.zoom; ctx.stroke();
        ctx.beginPath(); ctx.arc(xy[0],xy[1],((big?3.4:2.4))/cam.zoom,0,6.2832); ctx.fillStyle=col; ctx.fill();
      }
      if(m.name){ hitList.push({sx:W/2+(xy[0]-cam.cx*worldW)*cam.zoom, sy:H/2+(xy[1]-cam.cy*worldH)*cam.zoom, m:m, col:col}); }
    }
  }
  function draw(){
    if(opts.idle && !reduce){ tgt.cx=base.cx+Math.sin(t*0.04)*0.014; tgt.cy=base.cy+Math.cos(t*0.033)*0.008; }
    cam.cx+=(tgt.cx-cam.cx)*.07; cam.cy+=(tgt.cy-cam.cy)*.07; cam.zoom+=(tgt.zoom-cam.zoom)*.07;
    hoverP+=((hoverM?1:0)-hoverP)*.18;
    choroT+=((choro?1:0)-choroT)*.08;
    ctx.setTransform(DPR,0,0,DPR,0,0); ctx.clearRect(0,0,W,H);
    ctx.fillStyle='#070d1c'; ctx.fillRect(0,0,W,H);
    ctx.save(); ctx.translate(W/2,H/2); ctx.scale(cam.zoom,cam.zoom); ctx.translate(-cam.cx*worldW,-cam.cy*worldH);
    for(var i=0;i<paths.length;i++){ var pp=paths[i], fill='#0f1626';
      if(choroT>0.01){ var rc=riskFill(pp.id); fill = rc?mix('#0f1626',rc[0],choroT*rc[1]):'#0f1626'; }
      ctx.fillStyle=fill; ctx.fill(pp.p);
      ctx.lineWidth=0.4/cam.zoom; ctx.strokeStyle='rgba(120,150,200,0.18)'; ctx.stroke(pp.p);
    }
    for(var r=0;r<routes.length;r++){ var rt=routes[r], A=pw(rt.a[0],rt.a[1]), B=pw(rt.b[0],rt.b[1]), C=ctrl(A,B);
      ctx.beginPath(); for(var u=0;u<=1.0001;u+=0.04){ var q=bez(A,B,C,u); if(u===0)ctx.moveTo(q[0],q[1]); else ctx.lineTo(q[0],q[1]); }
      ctx.strokeStyle=rt.color; ctx.lineWidth=(rt.w||1)/cam.zoom; if(rt.dash){ctx.setLineDash([6/cam.zoom,6/cam.zoom]); ctx.lineDashOffset=-t*0.7/cam.zoom;} ctx.stroke(); ctx.setLineDash([]);
      if(!reduce){ for(var k=0;k<5;k++){ var tt=((t*0.1)+(r*0.13)-k*0.02); tt=tt-Math.floor(tt); var qq=bez(A,B,C,tt); ctx.beginPath(); ctx.arc(qq[0],qq[1],(1.8-k*0.3)/cam.zoom,0,6.2832); ctx.fillStyle=rgba(rt.pulse||'#5ccbff',0.8-k*0.14); ctx.fill(); } }
    }
    hitList.length=0; markers(vessels,false); markers(highlights,true);
    ctx.restore();
  }
  function loop(){ t+=0.016*(window.__SHIP_SPEED||1); draw(); raf=requestAnimationFrame(loop); }
  function start(){ if(running)return; running=true; if(reduce)draw(); else loop(); }
  function stop(){ running=false; if(raf)cancelAnimationFrame(raf); raf=null; }
  mapDraws.push(function(){ if(running||reduce) draw(); });
  resize();
  if('ResizeObserver' in window){ var ro=new ResizeObserver(function(){ resize(); if(reduce)draw(); }); ro.observe(canvas); }
  else window.addEventListener('resize',function(){resize(); if(reduce)draw();});
  function onMove(e){ if(!hoverCb) return; var r=canvas.getBoundingClientRect(); var mx=e.clientX-r.left, my=e.clientY-r.top, best=null, bd=1e9;
    for(var i=0;i<hitList.length;i++){ var h=hitList[i], dx=h.sx-mx, dy=h.sy-my, d=dx*dx+dy*dy; if(d<bd){ bd=d; best=h; } }
    var hit=(best && bd<=30*30)?best:null;
    canvas.style.cursor=hit?'pointer':'';
    var newM = hit?hit.m:null; if(newM!==hoverM){ hoverM=newM; if(reduce||!running) draw(); }
    if(hit){ lastHover=hit; hoverCb(hit); } else if(lastHover){ lastHover=null; hoverCb(null); } }
  function onLeave(){ hoverM=null; if(reduce||!running) draw(); if(lastHover){ lastHover=null; canvas.style.cursor=''; if(hoverCb)hoverCb(null); } }
  /* hover/tooltip is an interaction, not motion — bind it even under prefers-reduced-motion */
  canvas.addEventListener('mousemove',onMove); canvas.addEventListener('mouseleave',onLeave);
  return {
    onHover:function(cb){ hoverCb=cb; },
    hitTest:function(mx,my){ var best=null,bd=1e9; for(var i=0;i<hitList.length;i++){ var h=hitList[i], dx=h.sx-mx, dy=h.sy-my, d=dx*dx+dy*dy; if(d<bd){bd=d;best=h;} } return (best&&bd<=30*30)?best:null; },
    setCam:function(c){ tgt.cx=c.cx;tgt.cy=c.cy;tgt.zoom=c.zoom; base={cx:c.cx,cy:c.cy,zoom:c.zoom}; if(reduce){cam.cx=c.cx;cam.cy=c.cy;cam.zoom=c.zoom;} },
    setChoro:function(b){choro=b;}, setHighlights:function(h){highlights=h||[];}, setRoutes:function(r){routes=r||[];}, setVessels:function(v){vessels=v||[];},
    start:start, stop:stop, draw:draw
  };
}

