function animBar(){ var b=document.querySelector('.fcard[data-scene="0"] .fc-util-bar i'); if(b&&!b._d){ b._d=1; b.style.width=b.getAttribute('data-w')+'%'; } }
function animCM(){ var l=document.querySelector('.fcard[data-scene="1"] .cm-line'), a=document.querySelector('.fcard[data-scene="1"] .cm-area'); if(l&&!l._d){ l._d=1; if(!reduce&&l.getTotalLength){ var len=l.getTotalLength(); l.style.strokeDasharray=len; l.style.strokeDashoffset=len; l.getBoundingClientRect(); l.style.transition='stroke-dashoffset 1.5s cubic-bezier(.16,1,.3,1)'; l.style.strokeDashoffset='0'; } if(a){ a.style.transition='opacity 1.1s ease .35s'; a.style.opacity='1'; } } }

function animInsights(){
  var card=document.querySelector('.fcard[data-scene="5"]'); if(!card||card._d)return; card._d=1;
  card.classList.add('go');
  var cnt=card.querySelector('.pi-count b');
  if(cnt){ if(reduce){cnt.textContent='12';} else { var n=0; (function tick(){ n++; cnt.textContent=n; if(n<12)setTimeout(tick,70+n*4); })(); } }
}
function renderConv(i){
  if(convTimer){ clearTimeout(convTimer); clearTimeout(convTimer.b); }
  conv.innerHTML='';
  var q=document.createElement('div'); q.className='bub q'; q.textContent=QA[i].q; conv.appendChild(q);
  requestAnimationFrame(function(){ q.classList.add('show'); });
  if(reduce){ var a0=document.createElement('div'); a0.className='bub a show'; a0.innerHTML=QA[i].a; conv.appendChild(a0); return; }
  var ty=document.createElement('div'); ty.className='bub typing show'; ty.innerHTML='<i></i><i></i><i></i>';
  convTimer=setTimeout(function(){ conv.appendChild(ty); conv.scrollTop=conv.scrollHeight; },260);
  convTimer.b=setTimeout(function(){ if(cur!==i)return; if(ty.parentNode)ty.remove(); var a=document.createElement('div'); a.className='bub a'; a.innerHTML=QA[i].a; conv.appendChild(a); requestAnimationFrame(function(){a.classList.add('show'); conv.scrollTop=conv.scrollHeight;}); },1050);
}
function setScene(i){
  i=Math.max(0,Math.min(scenes.length-1,i)); if(i===cur)return; cur=i;
  cards.forEach(function(c,x){ c.classList.toggle('active', x===i); });
  chips.forEach(function(c,x){ c.classList.toggle('on', x===i); });
  dots.forEach(function(d,x){ d.classList.toggle('on', x===i); });
  if(deckMap){ var s=scenes[i]; deckMap.setCam(s.cam); deckMap.setChoro(s.choro); deckMap.setHighlights(s.hl); deckMap.setRoutes(s.routes); deckMap.start(); }
  renderConv(i);
  if(i===0)animBar(); if(i===1)animCM();
}
